def min_operations(H, W, K, grid):
    # Count the total number of 'o's in the grid
    total_o = sum(row.count('o') for row in grid)

    # Check if there is already a sequence of K consecutive 'o's
    for i in range(H):
        count = 0
        for j in range(W):
            if grid[i][j] == 'o':
                count += 1
            if count >= K:
                return 0

    # If there are fewer than K 'o's, return -1
    if total_o < K:
        return -1

    min_operations_needed = float('inf')

    # Check horizontal sequences
    for i in range(H):
        for j in range(0, W - K + 1):
            operations_needed = 0
            for k in range(K):
                if grid[i][j + k] == '.':
                    operations_needed += 1
            min_operations_needed = min(min_operations_needed, operations_needed)
            if min_operations_needed == K:
                return K

    # Check vertical sequences
    for j in range(W):
        for i in range(0, H - K + 1):
            operations_needed = 0
            for k in range(K):
                if grid[i + k][j] == '.':
                    operations_needed += 1
            min_operations_needed = min(min_operations_needed, operations_needed)
            if min_operations_needed == K:
                return K

    return min_operations_needed

# Read input
import sys
input = sys.stdin.read
data = input().split()

H = int(data[0])
W = int(data[1])
K = int(data[2])
grid = data[3:3+H]

# Calculate and print the result
result = min_operations(H, W, K, grid)
print(result)

class Solution:
    def minimumCoins(self, prices: List[int]) -> int:
        n = len(prices)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            for j in range(1, i + 1):
                dp[i] = min(dp[i], dp[i - j] + prices[j - 1])

        return dp[n]

class Solution:
    def minimumOperationsToMakeEqual(self, x: int, y: int) -> int:
        operations = 0
        while x != y:
            if x > y:
                if x % 11 == 0:
                    x //= 11
                elif x % 5 == 0:
                    x //= 5
                else:
                    x -= 1
            else:
                x += 1
            operations += 1
        return operations
